INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Auto Leveler$q$, $q$Automatically balances volume differences between speakers and takes without manual gain riding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Speech-optimized waveform$q$, $q$Color-coded track display that visually separates voice from music and sound effects for faster editing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Noise reduction and Auto EQ$q$, $q$One-click tools to clean up room tone, hiss and uneven tonal balance in interview recordings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Multi-track and X/Y recording$q$, $q$Supports multi-track sessions and stereo X/Y field recording for ambient and interview capture.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Chapter markers and publishing$q$, $q$Add chapter markers and export directly to podcast hosting platforms for faster episode turnaround.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Hindenburg Narrator script sync$q$, $q$Import scripts or spreadsheets and record with on-screen text for audiobook and voiceover work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Field Recorder mobile app$q$, $q$iOS app for professional-grade interview and field recording directly from an iPhone.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Cross-platform desktop app$q$, $q$Native Hindenburg PRO application for both macOS and Windows.$q$, 7);
