INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Narrower feature set than full DAWs like Pro Tools or Adobe Audition for music-heavy production$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Field Recorder mobile app is iOS only, with no Android version$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Perpetual license and subscription are sold separately per product, which can add up across PRO and Narrator$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Smaller plugin and third-party integration ecosystem than larger DAWs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$No fully free desktop tier for the PRO editor$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$What is Hindenburg used for?$q$, $q$Hindenburg is spoken-word audio editing software used by podcasters, radio journalists, documentary producers and audiobook narrators to record, clean up and mix interview-based and narration audio.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$How much does Hindenburg PRO cost?$q$, $q$Hindenburg PRO is available as a monthly subscription around $12/month or as a one-time perpetual license around $95, depending on whether you prefer ongoing access or outright ownership.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Is Hindenburg available for Windows and Mac?$q$, $q$Yes, Hindenburg PRO runs natively on both macOS and Windows.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Does Hindenburg have a free version?$q$, $q$The Field Recorder mobile app has a free Lite version limited to 60-second recordings. The desktop PRO editor does not have a permanently free tier but typically offers a trial period.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Who founded Hindenburg?$q$, $q$Hindenburg was founded in 2008 in Copenhagen by Nick Dunkerley and Preben Friis, both former radio professionals at Danish National Radio (DR).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$How is Hindenburg different from Adobe Audition or Descript?$q$, $q$Hindenburg focuses narrowly on spoken-word audio with automated leveling, EQ and noise tools and a speech-optimized waveform, whereas Adobe Audition is a general-purpose DAW and Descript centers on text-based, transcript-driven editing.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Podcast production$q$, $q$Independent and professional podcasters use Hindenburg PRO to record, level and mix multi-guest interview episodes quickly.$q$, $q$Podcasters and podcast producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Radio journalism$q$, $q$Broadcast and public radio journalists use Hindenburg to edit field interviews and produce broadcast-ready segments under deadline pressure.$q$, $q$Radio and broadcast journalists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Audiobook and voiceover narration$q$, $q$Narrators use Hindenburg Narrator to record scripted audiobook chapters and e-learning voiceovers with on-screen script sync.$q$, $q$Audiobook narrators and voiceover artists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Field Recorder Lite$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["iOS mobile recording","Recordings capped at 60 seconds","Basic field recording features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Field Recorder Full$q$, $q$$4.99$q$, $q$one-time$q$, NULL, $q$["Unlimited recording length","Professional field recording on iPhone"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Hindenburg PRO Subscription$q$, $q$$12/month$q$, $q$monthly$q$, NULL, $q$["Full desktop editor","Auto Leveler and Auto EQ","Noise reduction","Multi-track and X/Y recording"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$Hindenburg PRO Perpetual License$q$, $q$$95$q$, $q$one-time$q$, NULL, $q$["Full desktop editor with permanent license","Auto Leveler and Auto EQ","Noise reduction","Free minor updates"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hindenburg is a family of spoken-word audio editing tools designed by former radio journalists for people who tell stories with sound. Rather than trying to be a general-purpose digital audio workstation like Pro Tools or Adobe Audition, Hindenburg narrows its focus to the specific needs of interview-based and narrative audio: leveling uneven voice levels, removing background noise, organizing multi-track conversations, and exporting broadcast-ready files quickly.$q$, $q$The company, Hindenburg Systems ApS, was founded in Copenhagen in 2008 by Nick Dunkerley and Preben Friis, both veterans of Danish National Radio (DR). Their goal was to build editing software light and intuitive enough that a reporter on deadline could focus on the story rather than fighting complicated software. That journalist-first philosophy still shapes the product line today, from the flagship Hindenburg PRO editor to the mobile Field Recorder app and the audiobook-focused Narrator tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hindenburg PRO's signature feature is its speech-optimized waveform display, which visually distinguishes voice tracks from music and sound-effect tracks, making it easier to spot pacing issues, silences and volume inconsistencies at a glance. Its Auto Leveler automatically evens out volume differences between speakers or takes, while Auto EQ and built-in noise reduction clean up room tone and hiss without manual filter tweaking, cutting post-production time significantly compared to manual mixing in a traditional DAW.$q$, $q$Beyond editing, Hindenburg PRO includes multi-track recording, X/Y stereo field recording support for capturing ambient audio, chapter and marker tools for podcast episode navigation, and direct publishing integrations with common podcast hosting platforms. Hindenburg Narrator extends the same engine to long-form narration, letting voiceover artists and audiobook narrators import a script or spreadsheet of lines and see the text on-screen as they record, which speeds up multi-take narration work for e-learning and audiobook production. Hindenburg Field Recorder brings a simplified, professional-grade recording interface to iPhone for journalists capturing interviews on the go.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bccb27f4-8fb2-457f-97ab-9ab82be7cb63', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hindenburg uses a mixed pricing model across its product line. Hindenburg PRO, the core editor, is available either as a monthly subscription priced around $12/month or as a one-time perpetual license priced around $95, letting customers choose between low upfront cost and long-term ownership. Hindenburg Narrator is offered as a separate subscription priced around $15/month, reflecting its specialized script-and-record workflow for narration professionals.$q$, $q$Hindenburg Field Recorder follows a freemium mobile model: a free Lite version is available on the iOS App Store with recordings capped at 60 seconds, while the full version unlocks unlimited recording length for a small one-time purchase price of under $5. There is no permanently free tier for the desktop PRO editor, but trial periods are typically offered so podcasters and journalists can evaluate the automated leveling and noise tools before committing to a subscription or license.$q$]::text[], 2);
