INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Automated outreach sequencing$q$, $q$Sends multichannel, personalized outreach campaigns to candidates with automated follow-up.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$AI resume and voice screening$q$, $q$Pre-qualifies candidates using AI-based analysis of resumes and recorded voice screenings.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Interview scheduling automation$q$, $q$Automates coordination and scheduling of candidate interviews with hiring teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Recruiting analytics$q$, $q$Dashboards tracking pipeline health, sourcing channel performance and diversity metrics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$ATS integrations$q$, $q$Native integrations with 40-plus applicant tracking systems so HireEZ runs on top of existing hiring infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Market insight and talent data$q$, $q$Provides market intelligence on talent supply, compensation and skill availability to inform sourcing strategy.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Broad sourcing reach across 45-plus channels beyond typical professional network searches$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Integrates with existing ATS rather than requiring a full platform migration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$AI screening and scheduling automation reduce manual recruiter workload$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Consolidation pricing model can replace several separate point solutions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Strong fit for high-volume technical and specialized-role sourcing$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Solo Recruiter plan at roughly $494/month is expensive for individual or freelance recruiters$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Enterprise pricing is custom and not transparent without a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Requires an existing ATS to get full value, adding integration complexity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$AI screening accuracy depends heavily on quality of role requirement data entered$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Steeper learning curve for teams new to outbound, rather than inbound, recruiting workflows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$What is HireEZ used for?$q$, $q$HireEZ is an AI-powered outbound recruiting platform used to source, engage, screen and schedule passive candidates across more than 45 online channels, layered on top of an existing applicant tracking system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$How much does HireEZ cost?$q$, $q$HireEZ offers a Solo Recruiter plan at approximately $494 per month with a 7-day free trial, and an Enterprise plan with custom pricing based on the tools being consolidated and replaced.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Does HireEZ replace my ATS?$q$, $q$No, HireEZ is designed to integrate with and run on top of an organization's existing applicant tracking system through more than 40 native integrations rather than replacing it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Who founded HireEZ?$q$, $q$HireEZ was founded in 2015 by Steven Jiang and Xinwen Zhang under the original name Hiretual, rebranding to HireEZ in 2022.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$What is HireEZ's outbound recruiting model?$q$, $q$Outbound recruiting means proactively finding and engaging passive candidates who have not applied, rather than only relying on inbound applications, using AI-ranked sourcing and multichannel outreach.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$How is HireEZ different from LinkedIn Recruiter?$q$, $q$HireEZ sources across 45-plus channels beyond a single professional network, adds AI screening, CRM and analytics on top of sourcing, and is designed to consolidate multiple recruiting point tools rather than functioning as a single sourcing database.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Enterprise talent acquisition$q$, $q$Large in-house recruiting teams use HireEZ to consolidate sourcing, CRM, outreach and screening tools into one platform running on their existing ATS.$q$, $q$Enterprise talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Technical and specialized hiring$q$, $q$Recruiters sourcing hard-to-fill technical or niche roles use HireEZ's 45-plus channel search to find passive candidates beyond standard job boards.$q$, $q$Technical recruiters and hiring managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Independent recruiter sourcing$q$, $q$Solo recruiters and small agency teams use the Solo Recruiter plan to access AI sourcing and outreach without enterprise integration overhead.$q$, $q$Independent recruiters and small agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Solo Recruiter$q$, $q$$494/month$q$, $q$monthly$q$, NULL, $q$["Individual recruiter access","7-day free trial","AI sourcing across 45+ channels","Outreach and CRM tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual/custom$q$, NULL, $q$["4-week verification period","40+ native ATS integrations","AI screening and interview scheduling","Recruiting analytics and reporting","Unlimited working sessions during trial"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HireEZ is an AI-powered outbound recruiting platform built to help talent acquisition teams proactively source and engage passive candidates rather than waiting for inbound applications. Founded in 2015 as Hiretual and rebranded to HireEZ in 2022 alongside a $26 million Series B raise, the Mountain View-based company has positioned itself around a distinct category it calls 'outbound recruiting,' aggregating candidate data from more than 45 online channels and layering AI-based matching, screening and outreach automation on top.$q$, $q$Unlike a traditional applicant tracking system, HireEZ is designed to integrate with, rather than replace, a company's existing ATS, connecting through more than 40 native integrations. This lets recruiting teams keep their system of record intact while consolidating sourcing, CRM, outreach, screening and scheduling tools that would otherwise require several separate point solutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HireEZ's core sourcing engine searches across 45-plus channels, including professional networks and technical communities, and uses AI to rank and surface candidates matching a role's requirements, market data, and skill signals. A built-in candidate relationship management (CRM) system lets recruiters organize talent pools, track engagement history, and nurture passive candidates over time rather than treating sourcing as a one-off search.$q$, $q$On top of sourcing, HireEZ automates multichannel outreach sequencing so recruiters can message candidates across email and other channels with less manual follow-up, and it includes AI-based resume and voice screening tools to pre-qualify candidates before a human interview. Interview scheduling automation and recruiting analytics dashboards round out the platform, giving talent leaders visibility into pipeline velocity, channel performance and sourcing ROI.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HireEZ's pricing splits into two tiers. The Solo Recruiter plan is priced at approximately $494 per month and includes a 7-day free trial, aimed at individual recruiters or very small teams that want the AI sourcing and outreach engine without a full enterprise integration rollout.$q$, $q$The Enterprise plan uses custom pricing that is explicitly configured around the stack of point tools a customer is replacing rather than a flat per-seat rate, and includes a four-week guided verification period with unlimited working sessions before a company commits contractually. This consolidation-based pricing model is central to HireEZ's sales pitch, positioning the platform as a way to replace four to six separate recruiting tools with one subscription running on top of an existing ATS.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75de4905-e02e-4641-aa2f-074c25a04d63', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
