INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Cookie-free tracking$q$, $q$Tracks visitors without setting cookies or collecting personal identifiers, simplifying privacy compliance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Single-binary self-hosting$q$, $q$Runs as one binary with embedded DuckDB and NSQ, avoiding external database or queue dependencies.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Funnels and ecommerce tracking$q$, $q$Tracks multi-step conversion funnels and ecommerce transaction revenue in unified dashboards.$q$, 2);
