INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Google Search Console integration$q$, $q$Pulls search query and ranking data directly into HitKeep dashboards.$q$, 4);
