INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$REST API and webhooks$q$, $q$Provides a REST API and signed webhooks for integrating analytics events into other systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Full data export$q$, $q$Allows complete export of collected analytics data in multiple formats for portability.$q$, 7);
