INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Native ecommerce, funnel and AI crawler tracking beyond basic pageview analytics$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Multi-client reporting makes it well-suited for agencies managing several sites$q$, 3);
