INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Cloud free tier caps retention at 60 days, which may be short for long-term trend analysis$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Smaller ecosystem and community size compared to established players like Matomo or Plausible$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$EU/US-only cloud hosting regions may not suit all data residency needs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Self-hosting still requires basic server management skills despite the single-binary design$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$What is HitKeep used for?$q$, $q$HitKeep is used as a privacy-first, cookie-free web analytics platform to track pageviews, events, funnels, ecommerce revenue and search performance, either self-hosted or via a managed cloud service.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Is HitKeep free?$q$, $q$Yes, self-hosting HitKeep is free indefinitely. The managed cloud service also has a free tier for up to 3 sites, with paid Pro and Business tiers for higher limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Is HitKeep open source?$q$, $q$Yes, HitKeep is MIT-licensed open-source software with its source code publicly available on GitHub.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Does HitKeep use cookies?$q$, $q$No, HitKeep's default tracking sets no cookies and avoids collecting personal identifiers, and it honors Do Not Track browser signals.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Can HitKeep track ecommerce sales?$q$, $q$Yes, HitKeep tracks ecommerce transaction revenue alongside pageviews, events, funnels and campaign attribution in its dashboards.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$How does HitKeep compare to Google Analytics?$q$, $q$HitKeep is cookie-free, self-hostable and open source, giving users full data ownership, whereas Google Analytics relies on cookies and keeps data within Google's infrastructure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Privacy-compliant website analytics$q$, $q$Organizations subject to strict data protection requirements use HitKeep's cookie-free tracking to measure traffic without consent banners.$q$, $q$Privacy-conscious businesses and compliance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Self-hosted analytics infrastructure$q$, $q$Developers and technical teams self-host HitKeep's single binary to keep full control over analytics data and infrastructure.$q$, $q$Developers and technical teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Agency multi-site reporting$q$, $q$Marketing and SEO agencies use HitKeep's Business tier to manage analytics reporting across up to 50 client websites.$q$, $q$Marketing and SEO agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited sites and members","Full feature access","Single-binary deployment","Complete data ownership"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Cloud Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["3 sites","3 team members","60-day data retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Cloud Pro$q$, $q$в‚¬150/year$q$, $q$annual$q$, NULL, $q$["10 sites","5 team members","1-year data retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$Cloud Business$q$, $q$в‚¬390/year$q$, $q$annual$q$, NULL, $q$["50 sites","20 team members","3-year data retention"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$HitKeep is an open-source web analytics platform built around privacy and data ownership, offering an alternative to cookie-based tools like Google Analytics. Its architecture is unusually lightweight for a self-hosted analytics tool: it ships as a single binary with an embedded DuckDB database and NSQ message queue, meaning teams can run a full analytics stack without provisioning separate database or queue infrastructure.$q$, $q$The project is MIT-licensed with source code available on GitHub, and it can be deployed either as a fully self-hosted instance at no cost, or used through a managed cloud service hosted in the EU or US. This dual model lets privacy-focused technical teams retain full control of their data while still offering a low-friction option for teams that prefer a managed service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$HitKeep tracks pageviews, custom events, conversion goals, multi-step funnels and ecommerce transaction revenue, alongside UTM-based campaign attribution and referral source tracking. It automatically distinguishes AI crawler and bot traffic from genuine human visits, and pulls Google Search Console data directly into its dashboards so search performance and on-site behavior can be reviewed together.$q$, $q$By default, HitKeep sets no cookies, avoids collecting personal identifiers, and honors Do Not Track signals, with configurable retention windows to support privacy compliance without a consent banner. Additional capabilities include multi-client reporting for agencies, automatic capture of outbound clicks, downloads and form submissions, scheduled email reports, a REST API with signed webhooks, QR code campaign tracking, and full data export.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('908dae33-8b4a-4b73-8ca9-33e3eb8522aa', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$HitKeep's self-hosted deployment is free to run indefinitely, with no feature restrictions, appealing to developers and organizations that want complete control over their infrastructure and data residency. For teams that prefer not to manage hosting, HitKeep's cloud service starts with a Free tier covering 3 sites, 3 team members and 60 days of retention.$q$, $q$Paid cloud tiers scale from there: Pro is priced at в‚¬150 per year for up to 10 sites, 5 members and 1 year of data retention, while Business is priced at в‚¬390 per year for up to 50 sites, 20 members and 3 years of retention, targeting agencies that manage analytics across many client websites from a single account.$q$]::text[], 2);
