INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$What is Hive used for?$q$, $q$Hive is used as an all-in-one project management platform combining task tracking, Gantt and Kanban views, native chat, email integration and time tracking for teams of all sizes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Is Hive free to use?$q$, $q$Yes, Hive offers a Free plan for up to 10 workspace members with 200MB storage and unlimited tasks. Paid plans start at $5 per user per month for additional features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Who founded Hive?$q$, $q$Hive was founded in 2015 by John Furneaux, Eric Typaldos and Eric Maciel, and is headquartered in New York City.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Does Hive have an AI assistant?$q$, $q$Yes, Hive includes an AI Assistant available starting on the Starter plan, which helps summarize project status and automate routine tasks.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$How does Hive pricing work?$q$, $q$Hive has a Free plan, a Starter plan at $5/user/month, a Teams plan at $12/user/month, and a custom-priced Enterprise plan, with annual billing saving about 33% versus monthly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$How is Hive different from Asana or Monday.com?$q$, $q$Hive bundles native team chat and email directly into the same workspace as project tasks, whereas Asana and Monday.com typically rely on external chat tools like Slack for team communication.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Cross-functional project management$q$, $q$Marketing, product and operations teams use Hive's flexible views to plan and track projects across departments in one workspace.$q$, $q$Cross-functional teams and project managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Agency and creative workflows$q$, $q$Creative and marketing agencies use Hive's proofing, approval and forms features to manage client deliverables and intake requests.$q$, $q$Creative agencies and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Remote team collaboration$q$, $q$Distributed teams use Hive's native chat and email integration to coordinate work without switching between separate communication tools.$q$, $q$Remote and distributed teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Free$q$, $q$$0$q$, $q$forever$q$, NULL, $q$["Up to 10 workspace members","200MB storage","Unlimited tasks","Native chat and email integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Starter$q$, $q$$5/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited storage","Up to 10 projects","Gantt view","Cloud storage, Zoom and Slack integrations","AI Assistant"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Teams$q$, $q$$12/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited workspace members","Custom fields, labels and statuses","Shareable forms","Time tracking","Portfolios"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual/custom$q$, NULL, $q$["Enhanced security","Dedicated Customer Success Manager","Enterprise API","Professional Services access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hive is a cloud-based project management and productivity platform headquartered in New York City, founded in 2015 by John Furneaux, Eric Typaldos and Eric Maciel. The company has raised roughly $28 million in venture funding, including a 2021 Series A round led by Comcast Ventures, and counts brands such as WeWork, Netflix and Uber among its customer base.$q$, $q$Hive positions itself as an all-in-one work management tool, combining project planning, native team chat, email and time tracking into a single workspace rather than requiring teams to stitch together separate apps for messaging and task management. This consolidation is central to how Hive differentiates itself from competitors like Asana, Monday.com and ClickUp.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hive's core feature is flexible project views: the same underlying project data can be displayed as a Gantt chart, Kanban board, calendar, spreadsheet-style table, or portfolio roll-up, letting different team members work in whichever view fits their role without re-entering data. Native team chat and direct messaging are built directly into the workspace, alongside email integration so users can send and receive email without leaving Hive.$q$, $q$Additional features include time tracking against tasks and projects, shareable intake forms that convert submissions into tasks automatically, resource and workload management, proofing and approval workflows for creative and content review cycles, and an AI Assistant that helps summarize status updates and automate routine work. Hive also integrates with Slack, Zoom and major cloud storage providers, and Enterprise customers get access to a dedicated API.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e05880b5-22df-4a10-a038-632711020632', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hive's Free plan costs $0 and covers up to 10 workspace members with 200MB of storage, unlimited tasks, collaborative notes, native chat and email integration, suitable for individuals or very small teams. The Starter plan is $5 per user per month and unlocks unlimited storage, up to 10 projects, Gantt views, cloud storage integrations, an in-app calendar, and Zoom, Slack and AI Assistant access.$q$, $q$The Teams plan, at $12 per user per month, removes the member cap and adds custom fields, shareable forms, time tracking and portfolios, while Enterprise offers custom pricing with enhanced security, a dedicated Customer Success Manager, Enterprise API access and Professional Services support. Annual billing saves about 33% versus monthly, and a 14-day free trial with full features is available without a credit card, alongside non-profit discounts on request.$q$]::text[], 2);
