INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$AI voice inspections$q$, $q$Records and transcribes hive inspection audio automatically, then drafts structured notes using locally-run AI models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Local AI processing$q$, $q$Uses open-source Faster-Whisper and Ollama models that can run entirely on the user's own hardware for privacy.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Apiary and hive tracking$q$, $q$Organizes multiple apiaries and individual hive configurations in one place.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Queen management$q$, $q$Tracks individual queen lineage and status across hives and generations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Batch and quick inspections$q$, $q$Supports fast yard walk-throughs and batch inspection entry across multiple hives in one session.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Treatment and harvest tracking$q$, $q$Logs pest and disease treatments alongside honey harvest records.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Hive scale integration$q$, $q$Integrates hive scale monitoring data to track weight trends indicating honey flow or swarm risk.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Collaboration and sharing$q$, $q$Invites collaborators to shared apiaries and generates read-only views for mentors or clubs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Completely free and open source with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$AI voice transcription can run locally, keeping inspection data private$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Self-hostable via Docker Compose on a home server or Raspberry Pi$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Installable as an offline-capable Progressive Web App on mobile$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Full data import and export avoids vendor lock-in$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Still an actively developing project with possible breaking API changes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$No dedicated native iOS or Android app, relying instead on a PWA$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Local AI transcription requires sufficient hardware if self-hosting Ollama$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$No formal company or support team behind the project, being community-maintained$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Limited public track record compared to established commercial beekeeping software$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$What is Hive-Pal used for?$q$, $q$Hive-Pal is an open-source beekeeping management app used to track apiaries, hives, inspections, queen status and colony health, including AI-assisted voice inspection notes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Is Hive-Pal free?$q$, $q$Yes, Hive-Pal is completely free, both as a hosted web app and as a self-hosted deployment, since it is open-source software under the MIT license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Can Hive-Pal be self-hosted?$q$, $q$Yes, Hive-Pal includes a production-ready Docker Compose configuration that lets users self-host the full application on a home server, laptop or Raspberry Pi.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$How does the AI voice inspection feature work?$q$, $q$Beekeepers record audio while inspecting a hive, which Hive-Pal transcribes using the open-source Faster-Whisper model and then summarizes into structured notes using a locally-run Ollama language model.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Is my inspection data private with Hive-Pal?$q$, $q$Yes, since the AI transcription and note-drafting models can run locally on the user's own hardware, inspection audio and notes do not need to be sent to a third-party cloud service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Does Hive-Pal support multiple apiaries?$q$, $q$Yes, Hive-Pal lets beekeepers organize and manage multiple apiaries and individual hives, including queen lineage tracking and equipment planning across all of them.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Hobbyist hive tracking$q$, $q$Individual beekeepers replace paper inspection logs with structured digital records and AI-assisted voice notes.$q$, $q$Hobbyist beekeepers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Commercial apiary management$q$, $q$Small commercial beekeeping operations track many hives and apiaries, queen lineage, treatments and harvests in one system.$q$, $q$Commercial beekeepers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Privacy-focused self-hosting$q$, $q$Privacy-conscious beekeepers self-host Hive-Pal with local AI models to keep inspection data entirely off third-party servers.$q$, $q$Self-hosting and privacy-focused users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Browser-based access","No signup required for lightweight use","Full feature set"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Docker Compose deployment","Runs on home server, laptop or Raspberry Pi","Local AI voice transcription","Full data import and export"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hive-Pal is an open-source, mobile-first beekeeping management application built to replace paper logs and spreadsheets with structured digital tracking of apiaries, hives, inspections and colony health. The project's code is publicly available on GitHub (martinhrvn/hive-pal) under the MIT license, and it can be run as a hosted web app or fully self-hosted via Docker Compose on a home server, laptop, or even a Raspberry Pi.$q$, $q$The application is still in active development, with its maintainers describing the API as mostly stable but subject to occasional breaking changes as new features are added. Because it is entirely open source with no commercial entity behind it, there is no publicly documented founding date, funding history or company headquarters, unlike most other tools in this category.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hive-Pal's most distinctive feature is its AI-assisted voice inspection workflow: beekeepers record audio while inspecting a hive, and the app transcribes it automatically using the open-source Faster-Whisper model, then uses a locally-run Ollama language model to draft structured inspection notes covering brood pattern, stores, temperament and queen status. Because this runs on open-source models that can execute entirely on the user's own hardware, inspection audio never needs to leave the user's network.$q$, $q$Beyond voice inspections, the app supports structured and quick inspection logging, batch inspections across multiple hives, scheduled reminders, photo attachments, and treatment tracking. Colony management tools let beekeepers organize multiple apiaries, track queen lineage, plan equipment needs, and integrate hive scale data for weight-trend monitoring, while a unified calendar, colony health reports, harvest tracking and bulk actions support planning across an entire operation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hive-Pal is free in every deployment configuration. A hosted, browser-based version is available with no signup required for lightweight use, and the full application can be self-hosted indefinitely at no cost using the provided Docker Compose configuration, since the entire codebase is open source under the MIT license.$q$, $q$Because there is no subscription tier or paywalled feature set, beekeepers get the same functionality whether they use the hosted version or run it themselves, including the AI voice transcription pipeline (which requires local compute for Ollama if self-hosting) and full data import and export for complete portability of inspection records.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4b370b9c-680b-4e36-b5eb-96116115e439', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
