INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Member directory and profiles$q$, $q$Searchable, rich member directory with customizable profile fields for community members.$q$, 0);
