INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Groups and sub-communities$q$, $q$Organize members into interest-based groups, regional chapters or sub-communities.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Monetization tools$q$, $q$Support membership dues, paid content and sponsorship revenue directly within the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$AI-powered member matching$q$, $q$Recommends relevant connections and mentors within a community using AI matching from the Orbiit acquisition.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Email campaigns and notifications$q$, $q$Targeted communication tools for reaching members via email and in-app notifications.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Engagement and fundraising analytics$q$, $q$Dashboards for tracking member engagement, retention and fundraising performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Branded mobile app$q$, $q$Optional white-labeled mobile app add-on for community access on iOS and Android.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Comprehensive all-in-one platform covering directory, events, communication and monetization$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$AI-powered matching helps surface relevant connections within large communities$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Strong fit for associations and alumni networks with complex governance needs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Every plan includes unlimited end users regardless of tier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Hands-on onboarding support included across all pricing tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Entry-level pricing at $895/month is high relative to smaller community platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Top two tiers require custom pricing negotiations rather than transparent rates$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Steeper learning curve given the breadth of features aimed at large organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Not well suited for small creator communities or informal groups on a tight budget$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Add-ons like mobile app and multi-language support are priced separately$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$What is Hivebrite used for?$q$, $q$Hivebrite is used by associations, alumni networks and enterprise brands to build branded online communities with member directories, events, groups, communication tools and monetization features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$How much does Hivebrite cost?$q$, $q$Hivebrite's Core plan starts at $895 per month billed annually, Flex starts at $1,995 per month billed annually, and Prime and Custom Fit plans use custom pricing based on organizational needs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Who founded Hivebrite?$q$, $q$Hivebrite was founded in 2015 by CEO Jean Hamon and is headquartered in Paris, France.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Does Hivebrite have AI features?$q$, $q$Yes, Hivebrite gained AI-powered member matching capabilities through its acquisition of Orbiit, which recommends relevant connections and mentors within a community.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Is there a free trial for Hivebrite?$q$, $q$Hivebrite's public pricing does not list a free tier; interested organizations typically go through a discovery and demo process before committing to a plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$How is Hivebrite different from Mighty Networks or Circle?$q$, $q$Hivebrite is built for larger, structured organizations like associations and alumni networks with enterprise-grade monetization and governance tools, while Mighty Networks and Circle are more oriented toward individual creators and smaller paid communities.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Alumni network management$q$, $q$Universities and schools use Hivebrite to run branded alumni communities with directories, events and giving campaigns.$q$, $q$Universities and alumni relations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Professional association engagement$q$, $q$Trade and professional bodies use Hivebrite to manage member directories, events and communication at scale.$q$, $q$Professional and trade associations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Enterprise brand communities$q$, $q$Enterprises build branded customer or partner communities using Hivebrite's monetization and group management tools.$q$, $q$Enterprise brand and customer community teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Core$q$, $q$From $895/month$q$, $q$annual$q$, NULL, $q$["Member directory","Events and ticketing","Memberships","Connections","Monetization"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Flex$q$, $q$From $1,995/month$q$, $q$annual$q$, NULL, $q$["Everything in Core","Community champions","Deeper group management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Prime$q$, $q$Custom pricing$q$, $q$annual/custom$q$, NULL, $q$["Everything in Flex","Autonomous sub-communities","Multi-level governance"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$Custom Fit$q$, $q$Custom pricing$q$, $q$annual/custom$q$, NULL, $q$["Everything in Prime","Deep customization","Extended integrations","Bespoke workflows"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hivebrite is a Paris-based community engagement platform founded in 2015 by CEO Jean Hamon, built to help associations, alumni networks and enterprise brands run owned, branded online communities rather than relying on third-party social platforms. The company has raised close to $59 million in funding, including a $37 million Series B round in 2023 led by Quadrille Capital with continued backing from Insight Partners.$q$, $q$In 2023, Hivebrite acquired Orbiit, an AI-powered matching engine, adding intelligent member-to-member connection recommendations to its platform. This positions Hivebrite as a full 'community operating system' aimed primarily at large, structured organizations such as professional associations, alumni networks and enterprise brand communities that need directory, event, communication and monetization tools in one place.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Hivebrite provides a searchable member directory with rich profiles, event management with ticketing and online payment processing, and group or sub-community creation for organizing members by interest, region or chapter. Targeted communication tools, including email campaigns and in-app notifications, help organizations keep members engaged, while built-in analytics track engagement, retention and fundraising performance.$q$, $q$Monetization is a core capability, supporting membership dues, paid content and sponsorship management, and the platform's AI-powered matching, gained through the Orbiit acquisition, recommends relevant connections and mentors within a community based on shared interests or professional background. Optional add-ons across all plans include a branded mobile app, multi-language support, third-party data connectors and structured mentoring program tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hivebrite's Core plan starts at $895 per month billed annually and includes the full community operating system from the start: directory, events, memberships, connections and monetization. The Flex plan starts at $1,995 per month billed annually and adds community champion programs and deeper group management for organizations focused on peer-to-peer knowledge sharing.$q$, $q$The Prime and Custom Fit plans both use custom pricing determined after a discovery process, aimed respectively at mature multi-region communities needing autonomous sub-communities and governance, and large complex organizations needing deep customization and extended integrations. All plans include unlimited users, email campaigns, automation and AI features, and hands-on onboarding, with administrator and group management seats scaling by tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('08901206-af95-4614-be7a-942eac7c6ae2', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
