INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Native Gmail and Outlook shared inbox$q$, $q$Manage shared support or sales inboxes directly within Gmail or Outlook without a separate portal.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$AI agents and AI copilot$q$, $q$AI-powered tools that draft responses, summarize threads and automate routine customer replies.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Omnichannel support$q$, $q$Unified handling of email, live chat, help center, phone and WhatsApp channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Automation and round robin assignment$q$, $q$Rule-based automation and round robin ticket assignment to distribute workload across agents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Customer self-service portal$q$, $q$Branded portal letting customers track ticket status and browse help articles.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$SLAs and CSAT surveys$q$, $q$Service-level agreement tracking and customer satisfaction surveys on Pro and above.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Skill-based routing and AI QA$q$, $q$Routes tickets by agent skill and applies AI-driven quality assurance and insights on the Elite plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Enterprise security controls$q$, $q$SSO, HIPAA compliance support and custom roles available on the Elite plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Deep native integration with Gmail and Outlook avoids forcing agents into a separate portal$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Free plan available for small teams starting with structured customer service$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$AI copilot and AI agents help reduce manual response drafting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Clear tiered pricing scaling from Free through Elite for growing support needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$HIPAA and SSO support on the Elite plan suit regulated industries like healthcare$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Elite plan pricing at $85-95/user/month is expensive for larger support teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$All paid plans require a minimum of two seats, adding cost for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Advanced automation and skill-based routing gated behind higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Primarily optimized for Google Workspace and Outlook users rather than standalone use$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Less full-featured as a dedicated ticketing system compared to Zendesk for complex support operations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$What is Hiver used for?$q$, $q$Hiver is used as a shared inbox and AI-powered customer service platform built on Gmail and Google Workspace, handling email, chat, phone and WhatsApp support in one place.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Is Hiver free to use?$q$, $q$Yes, Hiver offers a Free plan covering shared inbox and ticketing across email, chat and help center channels. Paid plans start at $25 per user per month on the Growth tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Who founded Hiver?$q$, $q$Hiver was founded in 2011 under the name Grexit by Niraj Ranjan Rout and Nitesh Nandy, later rebranding to Hiver.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Does Hiver work with Outlook as well as Gmail?$q$, $q$Yes, while Hiver originated as a Gmail-native shared inbox tool, it also supports Outlook alongside its broader omnichannel platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$What AI features does Hiver offer?$q$, $q$Hiver includes AI agents and an AI copilot that draft responses and summarize conversation threads, plus AI-powered quality assurance and insights on the Elite plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$How does Hiver differ from Zendesk?$q$, $q$Hiver is built natively inside Gmail and Google Workspace so agents work from their existing inbox, while Zendesk is a standalone help desk platform requiring agents to work in a separate portal.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Shared support inbox management$q$, $q$Small and mid-market support teams manage a shared support@ inbox directly inside Gmail with ticketing and assignment.$q$, $q$Customer support teams on Google Workspace$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Omnichannel customer service$q$, $q$Growing teams consolidate email, chat, phone and WhatsApp support into a single Hiver workspace.$q$, $q$Mid-market customer service operations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Regulated industry support$q$, $q$Healthcare and other regulated organizations use Hiver's Elite plan for HIPAA-compliant, SSO-secured support operations.$q$, $q$Healthcare and regulated industry support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Shared inbox and ticketing","Email, chat and help center channels","24/7 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Growth$q$, $q$$25-$35/user/month$q$, $q$monthly or annual$q$, NULL, $q$["AI agents and AI copilot","Rule-based automation","Round robin assignment","Prebuilt analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Pro$q$, $q$$55-$65/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Customer portal","Slack channel management","SLAs and CSAT surveys","Advanced analytics","API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$Elite$q$, $q$$85-$95/user/month$q$, $q$monthly or annual$q$, NULL, $q$["AI QA and insights","Skill-based routing","Custom objects","SSO, HIPAA and custom roles"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Hiver is a customer service platform built natively on top of Gmail and Google Workspace, founded in 2011 under the name Grexit by co-founders Niraj Ranjan Rout (CEO) and Nitesh Nandy. The company later rebranded to Hiver and is now headquartered in San Francisco with a significant operations base in Bengaluru, India, having raised roughly $26 million in funding, including a $22 million Series B round in 2022 led by K1 Capital.$q$, $q$Hiver's original and still-defining idea was to let teams run a help desk directly from a shared Gmail inbox, such as a support@ address, without forcing agents into a separate ticketing portal. The platform has since expanded into a broader omnichannel customer service suite covering chat, phone, WhatsApp and a self-service knowledge base, while retaining its native Gmail and Outlook integration as its core differentiator.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Hiver's foundation is shared inbox management, letting teams collaboratively manage support, sales or operations email addresses with ticketing, assignment and internal notes, all inside the familiar Gmail or Outlook interface. On top of email, Hiver supports live chat, a self-service help center knowledge base, phone support and WhatsApp messaging as additional channels within the same platform.$q$, $q$More recent additions include AI agents and an AI copilot that can draft responses, summarize conversation threads and automate routine replies, alongside rule-based automation, round robin ticket assignment, and skill-based routing on higher tiers. Higher plans add a customer self-service portal, SLAs, CSAT surveys, advanced analytics, premium integrations, API access, and enterprise controls like SSO, HIPAA compliance support and custom roles.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('badfcb90-2ef7-4fee-a3ed-8a5021afbe5f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Hiver's Free plan costs $0 per month and includes shared inbox and ticketing across email, chat and help center channels, suited to teams just getting started with structured customer service. The Growth plan is priced between $25 and $35 per user per month depending on monthly or annual billing, and adds AI agents, an AI copilot, rule-based automation and prebuilt analytics.$q$, $q$The Pro plan, Hiver's most popular tier, runs $55 to $65 per user per month and adds a customer portal, SLAs, CSAT surveys and API access, while the Elite plan at $85 to $95 per user per month adds AI quality assurance, skill-based routing and enterprise security features like SSO and HIPAA support. All paid plans require a minimum of two seats.$q$]::text[], 2);
