INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$1,000+ device integrations$q$, $q$Unified support for over 1,000 smart home devices and services across Zigbee, Z-Wave, Matter, Thread and Wi-Fi.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Local-first automation engine$q$, $q$Runs automations locally on user-owned hardware rather than routing commands through manufacturer cloud servers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Lovelace dashboard UI$q$, $q$Fully customizable dashboard interface for visualizing and controlling connected devices.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$HACS community store$q$, $q$Community-maintained marketplace for custom integrations and dashboard cards beyond the core distribution.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Energy monitoring$q$, $q$Native dashboards for tracking electricity, gas and solar production over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Assist local voice control$q$, $q$Privacy-focused local voice assistant framework for controlling the home without cloud-based voice services.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Add-on system via Supervisor$q$, $q$Managed add-on ecosystem for extending functionality such as media servers or additional integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Mobile companion apps$q$, $q$Official iOS and Android apps for remote access, location-based automations and push notifications.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Completely free, open-source core with no feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Local-first architecture improves privacy and works during internet outages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Broadest device and integration support of any smart home platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Governed by a nonprofit (Open Home Foundation) rather than a single commercial vendor$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Optional Cloud subscription is inexpensive and directly funds project development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Steeper learning curve than plug-and-play hubs like SmartThings or Google Home$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Self-hosting requires dedicated hardware and basic technical maintenance skills$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Remote access and Alexa/Google Assistant integration require the paid Cloud add-on for easiest setup$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Community-maintained HACS integrations vary in quality and long-term support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$No official vendor support line, relying instead on community forums and documentation$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$What is Home Assistant used for?$q$, $q$Home Assistant is an open-source smart home platform used to unify and automate control of smart devices, such as lights, sensors, locks and thermostats, from over 1,000 supported integrations under local, privacy-focused control.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Is Home Assistant free?$q$, $q$Yes, the core Home Assistant software is completely free and open source with no feature restrictions. An optional Nabu Casa Cloud subscription costs about $6.50 per month or $65 per year for remote access and cloud backup convenience.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Who created Home Assistant?$q$, $q$Home Assistant was created by Paulus Schoutsen, who started it as a personal Python project in September 2013 and published it publicly on GitHub later that year.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$What is Nabu Casa's relationship to Home Assistant?$q$, $q$Nabu Casa, Inc is the commercial company founded by the Home Assistant team in 2018 that operates the optional Home Assistant Cloud subscription service, with all revenue funding full-time development of the open-source project.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Does Home Assistant require an internet connection?$q$, $q$No, Home Assistant runs and processes automations locally on user-owned hardware by default, so most core functionality continues working even without internet access.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$How does Home Assistant compare to SmartThings or Google Home?$q$, $q$Home Assistant offers broader device support, local-first processing and full user control since it is self-hosted and open source, while SmartThings and Google Home are simpler, cloud-dependent commercial hubs with narrower integration ecosystems.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$DIY smart home automation$q$, $q$Technically inclined users self-host Home Assistant to unify and automate devices from many different manufacturers under one system.$q$, $q$Smart home hobbyists and DIY enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Privacy-focused home control$q$, $q$Privacy-conscious users run Home Assistant locally to avoid sending home data and voice commands to big tech cloud services.$q$, $q$Privacy-focused homeowners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Energy monitoring and optimization$q$, $q$Households use Home Assistant's energy dashboards to track electricity, gas and solar production and optimize usage.$q$, $q$Homeowners monitoring energy consumption$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Home Assistant Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted open-source platform","1,000+ integrations","Local automation engine","Unlimited devices and users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Home Assistant Cloud (Nabu Casa)$q$, $q$$6.50/month$q$, $q$monthly$q$, NULL, $q$["Secure remote access without port forwarding","Automated encrypted backups","Alexa and Google Assistant integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$Home Assistant Cloud Annual$q$, $q$$65/year$q$, $q$annual$q$, NULL, $q$["Secure remote access without port forwarding","Automated encrypted backups","Alexa and Google Assistant integration","Discounted vs monthly billing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Home Assistant is a free, open-source smart home automation platform originally created by Paulus Schoutsen in September 2013 and published on GitHub later that year. Over more than a decade it has grown into one of the most active open-source projects on GitHub, now powering over a million homes with more than 1,000 supported device and service integrations spanning Zigbee, Z-Wave, Matter, Thread and Wi-Fi.$q$, $q$Unlike commercial smart home hubs that route commands through a manufacturer's cloud, Home Assistant is built around local-first control, running entirely on hardware the user owns. Its sustainability comes from Nabu Casa, Inc, a commercial companion company founded in 2018 by the core Home Assistant team and headquartered in Irvine, California, whose sole product, Home Assistant Cloud, funds full-time development of the open-source project. Governance was formalized in 2024 under the nonprofit Open Home Foundation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Home Assistant's dashboard is built on the customizable Lovelace UI framework, and its automation engine lets users build conditional rules across any connected device or sensor, regardless of manufacturer, since integrations are unified under a common data model. The Home Assistant Supervisor manages an add-on ecosystem for extending functionality, while HACS, a community-maintained store, provides additional custom integrations and dashboard elements beyond the official core distribution.$q$, $q$The platform includes native energy monitoring dashboards for tracking electricity, gas and solar generation, and Assist, a local voice assistant framework that lets users control their smart home by voice without sending audio to Amazon or Google. Official companion apps for iOS and Android provide remote dashboard access, location-based automation triggers and push notifications, and dedicated hardware like Home Assistant Green and Yellow gives less technical users a plug-and-play way to run the platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('caf4aea6-fd20-4af6-9d16-4a5cbc4d2503', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Home Assistant's core software is completely free and open source, with no feature restrictions or paywalls regardless of how it is installed, whether on a Raspberry Pi, a mini PC, a virtual machine, or official Home Assistant Green or Yellow hardware. Anyone can self-host the platform indefinitely at no cost.$q$, $q$The only paid offering is the optional Nabu Casa Home Assistant Cloud subscription, priced at approximately $6.50 per month or $65 per year, which adds secure remote access without manual router configuration, automated encrypted cloud backups, and one-click Amazon Alexa and Google Assistant voice integration. All revenue from this subscription funds ongoing development of the free, open-source core platform.$q$]::text[], 2);
